#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code for RQ 6.9.8)
# =============================================================================
"""
Step ID: step05
Step Name: Compute Inverse-Variance Weighted Mean Effect Size
RQ: results/ch6/6.9.8
Generated: 2026-01-20

PURPOSE:
Combine schema congruence effect sizes from accuracy and confidence using inverse-variance
weighting. NOTE: K=2 effect sizes is insufficient for formal meta-analysis (no heterogeneity
assessment). This is simple inverse-variance weighted combination only.

EXPECTED INPUTS:
- results/ch6/6.9.8/data/step04_schema_effects_extracted.csv (2 rows)
  Columns: measure, effect_size_d, SE_d, p_value, source_file, extraction_method, notes

EXPECTED OUTPUTS:
- results/ch6/6.9.8/data/step05_weighted_combination.csv (1 row)
  Columns: d_pooled, SE_pooled, CI_lower, CI_upper, w_accuracy, w_confidence,
           d_accuracy, d_confidence, interpretation, limitation_note

VALIDATION CRITERIA:
- |d_pooled| < 0.20 (negligible, supporting convergent NULL)
- Weights sum to 1.0 (normalized)
- CI_lower < d_pooled < CI_upper

g_code REASONING:
- Approach: Inverse-variance weighting (w = 1/SE²), pooled estimate = Σ(w*d) / Σ(w)
- Why this approach: Standard method for combining effect sizes when SE known
- Data flow: Load effects -> compute weights -> weighted mean -> CI -> interpret
- Expected performance: <1 second
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.8
LOG_FILE = RQ_DIR / "logs" / "step05_weighted_combination.log"
INPUT_FILE = RQ_DIR / "data" / "step04_schema_effects_extracted.csv"
OUTPUT_FILE = RQ_DIR / "data" / "step05_weighted_combination.csv"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console with flush."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 05: Compute Inverse-Variance Weighted Mean Effect Size")

        # =====================================================================
        # STEP 1: Load Extracted Effects
        # =====================================================================
        log("[LOAD] Loading extracted effect sizes...")
        df = pd.read_csv(INPUT_FILE)
        log(f"[LOADED] {len(df)} effect sizes")

        if len(df) != 2:
            raise ValueError(f"Expected 2 rows, got {len(df)}")

        # Extract values
        d_accuracy = df.loc[df['measure'] == 'Accuracy', 'effect_size_d'].values[0]
        d_confidence = df.loc[df['measure'] == 'Confidence', 'effect_size_d'].values[0]
        SE_accuracy = df.loc[df['measure'] == 'Accuracy', 'SE_d'].values[0]
        SE_confidence = df.loc[df['measure'] == 'Confidence', 'SE_d'].values[0]

        log(f"[INFO] Accuracy: d = {d_accuracy:.3f}, SE = {SE_accuracy:.3f}")
        log(f"[INFO] Confidence: d = {d_confidence:.3f}, SE = {SE_confidence:.3f}")

        # =====================================================================
        # STEP 2: Compute Inverse-Variance Weights
        # =====================================================================
        log("[COMPUTE] Computing inverse-variance weights...")

        w_accuracy_raw = 1 / SE_accuracy**2
        w_confidence_raw = 1 / SE_confidence**2

        log(f"[INFO] Raw weights: Accuracy = {w_accuracy_raw:.3f}, Confidence = {w_confidence_raw:.3f}")

        # Normalize weights to sum to 1
        w_total = w_accuracy_raw + w_confidence_raw
        w_accuracy = w_accuracy_raw / w_total
        w_confidence = w_confidence_raw / w_total

        log(f"[INFO] Normalized weights: Accuracy = {w_accuracy:.3f}, Confidence = {w_confidence:.3f}")
        log(f"[CHECK] Weight sum = {w_accuracy + w_confidence:.6f} (should be 1.0)")

        # =====================================================================
        # STEP 3: Compute Pooled Effect Size
        # =====================================================================
        log("[COMPUTE] Computing pooled effect size...")

        d_pooled = w_accuracy * d_accuracy + w_confidence * d_confidence

        log(f"[RESULT] Pooled effect size: d = {d_pooled:.3f}")

        # Pooled SE
        SE_pooled = 1 / np.sqrt(w_accuracy_raw + w_confidence_raw)

        log(f"[RESULT] Pooled SE: {SE_pooled:.3f}")

        # 95% CI
        z_critical = 1.96
        CI_lower = d_pooled - z_critical * SE_pooled
        CI_upper = d_pooled + z_critical * SE_pooled

        log(f"[RESULT] 95% CI: [{CI_lower:.3f}, {CI_upper:.3f}]")

        # =====================================================================
        # STEP 4: Interpret Results
        # =====================================================================
        log("[INTERPRET] Interpreting pooled effect size...")

        abs_d = abs(d_pooled)

        if abs_d < 0.20:
            interpretation = "Negligible effect (|d| < 0.20), convergent NULL confirmed"
            log("[INTERPRETATION] Negligible effect, convergent NULL confirmed")
        elif abs_d < 0.50:
            interpretation = "Small effect (0.20 <= |d| < 0.50), convergent NULL NOT confirmed"
            log("[INTERPRETATION] Small but non-negligible effect, convergent NULL NOT confirmed")
        else:
            interpretation = "Medium/large effect (|d| >= 0.50), convergent NULL NOT confirmed"
            log("[INTERPRETATION] Medium or large effect, convergent NULL NOT confirmed")

        # Limitation note (K=2 insufficient for meta-analysis)
        limitation_note = ("K=2 effect sizes insufficient for formal meta-analysis. " +
                          "No heterogeneity assessment performed. " +
                          "Simple inverse-variance weighting only.")

        log("[NOTE] Limitation: K=2 insufficient for formal meta-analysis")

        # =====================================================================
        # STEP 5: Create Output DataFrame
        # =====================================================================
        result = pd.DataFrame([{
            'd_pooled': d_pooled,
            'SE_pooled': SE_pooled,
            'CI_lower': CI_lower,
            'CI_upper': CI_upper,
            'w_accuracy': w_accuracy,
            'w_confidence': w_confidence,
            'd_accuracy': d_accuracy,
            'd_confidence': d_confidence,
            'interpretation': interpretation,
            'limitation_note': limitation_note
        }])

        # =====================================================================
        # STEP 6: Validate Results
        # =====================================================================
        log("[VALIDATION] Checking weighted combination...")

        errors = []

        # Check row count
        if len(result) != 1:
            errors.append(f"Expected 1 row, got {len(result)}")
        else:
            log("[PASS] Row count: 1")

        # Check SE positive
        if SE_pooled <= 0:
            errors.append(f"Non-positive SE_pooled: {SE_pooled}")
        else:
            log("[PASS] SE_pooled > 0")

        # Check CI ordering
        if not (CI_lower < d_pooled < CI_upper):
            # Allow edge case where d_pooled is at CI boundary
            if not (CI_lower <= d_pooled <= CI_upper):
                errors.append(f"CI bounds violated: {CI_lower:.3f} <= {d_pooled:.3f} <= {CI_upper:.3f}")
        else:
            log("[PASS] CI ordering: CI_lower < d_pooled < CI_upper")

        # Check weights sum to 1
        weight_sum = w_accuracy + w_confidence
        if not np.isclose(weight_sum, 1.0, atol=1e-6):
            errors.append(f"Normalized weights don't sum to 1.0: {weight_sum:.9f}")
        else:
            log("[PASS] Weights sum to 1.0")

        # Check weights in [0, 1]
        if w_accuracy < 0 or w_accuracy > 1 or w_confidence < 0 or w_confidence > 1:
            errors.append(f"Weights out of range [0, 1]: w_acc={w_accuracy:.3f}, w_conf={w_confidence:.3f}")
        else:
            log("[PASS] Weights in [0, 1]")

        # Check CI width approximately 4*SE
        ci_width = CI_upper - CI_lower
        expected_width = 2 * z_critical * SE_pooled  # 2 * 1.96 * SE
        if not np.isclose(ci_width, expected_width, rtol=0.01):
            errors.append(f"CI width mismatch: {ci_width:.3f} vs expected {expected_width:.3f}")
        else:
            log("[PASS] CI width approximately 4*SE_pooled")

        # Report interpretation
        log(f"[INFO] Pooled effect: d = {d_pooled:.3f} [{CI_lower:.3f}, {CI_upper:.3f}]")
        log(f"[INFO] {interpretation}")

        if abs_d < 0.20:
            log("[INFO] Effect size negligible (|d| < 0.20)")
            log("[INFO] Convergent NULL confirmed")
        else:
            log("[WARNING] Effect size non-negligible (|d| >= 0.20)")
            log("[WARNING] Convergent NULL NOT confirmed")

        # =====================================================================
        # STEP 7: Save Output
        # =====================================================================
        if errors:
            log("[VALIDATION] FAIL - Errors detected:")
            for error in errors:
                log(f"  - {error}")
            raise ValueError(f"Validation failed with {len(errors)} error(s)")

        log("[VALIDATION] PASS - All checks passed")
        log("[NOTE] Limitation acknowledged: K=2 insufficient for formal meta-analysis")

        result.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] Output: {OUTPUT_FILE}")

        log("[SUCCESS] Step 05 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        import traceback
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
